185	    fn is_builtin_excluded_all_seven_names() {
186	        for name in &[
187	            ".git",
188	            "target",
189	            "node_modules",
190	            "__pycache__",
191	            "vendor",
192	            "dist",
193	            ".next",
194	        ] {
195	            let p = Path::new(name).join("file.rs");
196	            assert!(is_builtin_excluded(&p), "{} should be excluded", name);
197	        }
198	    }
