207	        assert!(!is_builtin_excluded(Path::new("src/lib.rs")));
208	        assert!(!is_builtin_excluded(Path::new("src/core.rs")));
209	    }
210	
211	    #[test]
212	    fn is_builtin_excluded_partial_name_does_not_match() {
