216	    }
217	
218	    #[test]
219	    fn collect_from_directory_skips_builtin_excluded_dirs() {
220	        let dir = tempfile::tempdir().unwrap();
221	        let target_dir = dir.path().join("target");
222	        std::fs::create_dir_all(&target_dir).unwrap();
223	        let body = r#"pub fn accumulate_sum(a: i32, b: i32) -> i32 {
224	    let sum = a + b;
225	    let extra = sum * 2;
226	    let more = extra + a;
227	    let result = more + b;
228	    result
229	}
230	"#;
231	        std::fs::write(target_dir.join("excluded.rs"), body).unwrap();
232	        std::fs::write(dir.path().join("keep.rs"), body).unwrap();
233	        let gs = build_glob_set(&[]).unwrap();
234	        let mut functions = Vec::new();
235	        let mut errors = Vec::new();
236	        collect_from_directory(dir.path(), &gs, &mut functions, &mut errors);
237	        assert!(errors.is_empty());
238	        // only keep.rs scanned, excluded.rs inside target/ is pruned
239	        assert_eq!(functions.len(), 1);
240	    }
241	
242	    #[test]
243	    fn collect_from_single_file_skips_builtin_excluded_path() {
244	        let dir = tempfile::tempdir().unwrap();
245	        let node_modules = dir.path().join("node_modules");
246	        std::fs::create_dir_all(&node_modules).unwrap();
247	        let path = node_modules.join("bad.rs");
248	        std::fs::write(&path, "fn foo() {}").unwrap();
249	        let gs = build_glob_set(&[]).unwrap();
250	        let mut functions = Vec::new();
251	        let mut errors = Vec::new();
252	        collect_from_single_file(&path, &gs, &mut functions, &mut errors);
253	        assert_eq!(functions.len(), 0);
254	        assert!(errors.is_empty());
255	    }
256	
257	    // --- glob ---
