77	pub fn jaccard(a: &[u64], b: &[u64]) -> f64 {
78	    if a.is_empty() && b.is_empty() {
79	        return 1.0;
80	    }
81	    let set_a: HashSet<u64> = a.iter().copied().collect();
82	    let set_b: HashSet<u64> = b.iter().copied().collect();
83	    let intersection = set_a.intersection(&set_b).count();
84	    let union = set_a.union(&set_b).count();
85	    if union == 0 {
86	        return 0.0;
87	    }
88	    intersection as f64 / union as f64
89	}
