        let a = vec![1u64, 2, 3, 4];
        let b = vec![3u64, 4, 5, 6];
        let score = jaccard(&a, &b);
        // intersection={3,4}, union={1,2,3,4,5,6} => 2/6
        assert!((score - 2.0 / 6.0).abs() < 1e-9);
    }

