66	fn function_with_exact_lines(lines: usize, nodes: usize) -> String {
67	    if nodes < 20 {
68	        // Need a function with < 20 AST nodes in our counting scheme.
69	        // Empirically: a 5-line split signature has 19 nodes, which is below min_nodes=20.
70	        // This function also passes min_lines=4 (5 lines >= 4).
71	        return "pub fn fixture_fn(\n    x: i32,\n) -> i32 {\n    x\n}\n".to_string();
72	    }
73	
74	    // For lines < 4 (below min_lines=4 default), generate a function that spans exactly `lines` lines.
75	    // Tree-sitter: opening line + body lines + closing line = total.
76	    let body_content = if lines <= 2 {
77	        "    0\n".to_string()
78	    } else {
79	        let inner = lines - 2;
80	        let mut s = String::new();
81	        for i in 0..(inner.saturating_sub(1)) {
82	            s.push_str(&format!("    let _v{} = {};\n", i, i));
83	        }
84	        s.push_str("    0\n");
85	        s
86	    };
87	    format!("pub fn fixture_fn(x: i32, y: i32) -> i32 {{\n{}}}\n", body_content)
88	}
