92	        format!(
93	            "pub fn {p}_compute(a: i32, b: i32, c: i32) -> i32 {{\n\
94	             \x20   let step1 = a + b;\n\
95	             \x20   let step2 = step1 * c;\n\
96	             \x20   let step3 = step2 - a;\n\
97	             \x20   let step4 = step3 + b;\n\
98	             \x20   let step5 = step4 * 2;\n\
99	             \x20   let step6 = step5 + c;\n\
100	             \x20   let step7 = step6 - b;\n\
101	             \x20   let step8 = step7 + a;\n\
102	             \x20   step8\n\
103	             }}\n",
104	            p = p
105	        )
106	    };
107	    (body(prefix_a), body(prefix_b))
108	}
