        let score = crate::jaccard(&rust_funcs[0].node_hashes, &js_funcs[0].node_hashes);
        // Cross-language pairs should not score >= 0.82
        assert!(score < 0.82, "cross-language pair should score < 0.82, got {}", score);
    }

