// --- scan.rs:146 --- collect_from_directory filter_entry: delete first ! in
// `!e.file_type().is_dir() || !is_builtin_excluded(e.path())`
// Mutation: `e.file_type().is_dir() || !is_builtin_excluded(e.path())`
// With mutation: a builtin-excluded directory satisfies `is_dir()`, so filter_entry returns true
// and WalkDir recurses into it. The guard: a .rs file inside a builtin-excluded dir must NOT
// appear in results.
#[test]
fn collect_from_directory_skips_builtin_excluded_dirs() {
    let dir = tempfile::tempdir().expect("tempdir");
    let target_dir = dir.path().join("target");
    fs::create_dir(&target_dir).expect("create target/");
    let rs_file = target_dir.join("hidden.rs");
    fs::write(&rs_file, "fn inside_excluded() {}\n").expect("write rs");
    let empty_glob = build_glob_set(&[]).expect("glob");
    let mut functions = Vec::new();
    let mut errors = Vec::new();
    collect_from_directory(dir.path(), &empty_glob, None, &mut functions, &mut errors);
    assert!(errors.is_empty(), "unexpected errors: {:?}", errors);
    assert!(
        functions.is_empty(),
        "expected no functions from builtin-excluded dir, got: {:?}",
        functions
    );
}

use drywall::ast::{RUST_CONFIG, build_normalized_subtree, extract_functions, make_parser};
use proptest::prelude::*;

proptest! {
    #[test]
    fn hashing_deterministic_for_valid_fn(name in "[a-z][a-z0-9_]{0,10}") {
        let src = format!("fn {}(x: i32) -> i32 {{ let a = x + 1; a * 2 }}", name);
        let mut p1 = make_parser();
        let mut p2 = make_parser();
        let tree1 = p1.parse(&src, None).unwrap();
        let tree2 = p2.parse(&src, None).unwrap();
        let mut fns1 = Vec::new();
        let mut fns2 = Vec::new();
        extract_functions(tree1.root_node(), &src, "test.rs", &mut fns1);
        extract_functions(tree2.root_node(), &src, "test.rs", &mut fns2);
        prop_assert_eq!(fns1.len(), fns2.len());
        for (f1, f2) in fns1.iter().zip(fns2.iter()) {
            prop_assert_eq!(&f1.node_hashes, &f2.node_hashes, "same source must produce same hashes");
        }
    }

    #[test]
    fn normalized_subtree_deterministic(name in "[a-z][a-z0-9_]{0,10}") {
        let src = format!("fn {}() {{}}", name);
        let mut parser = make_parser();
        let tree = parser.parse(&src, None).unwrap();
        let root = tree.root_node();
        let s1 = build_normalized_subtree(root, &src, &RUST_CONFIG);
        let s2 = build_normalized_subtree(root, &src, &RUST_CONFIG);
        prop_assert_eq!(s1, s2, "build_normalized_subtree must be deterministic");
    }

    #[test]
    fn extract_functions_count_stable(name in "[a-z][a-z0-9_]{0,8}") {
        let src = format!(
            "fn {0}(x: i32) -> i32 {{ x + 1 }}\nfn {0}_b(y: i32) -> i32 {{ y * 2 }}",
            name
        );
        let mut parser = make_parser();
        let tree = parser.parse(&src, None).unwrap();
        let mut fns1 = Vec::new();
        let mut fns2 = Vec::new();
        extract_functions(tree.root_node(), &src, "f.rs", &mut fns1);
        extract_functions(tree.root_node(), &src, "f.rs", &mut fns2);
        prop_assert_eq!(fns1.len(), fns2.len(), "repeated extraction must yield same count");
    }
}

use clap::Parser;
use drywall::{Config, execute_cli, run};
use std::process;

#[derive(Parser)]
#[command(
    name = "drywall",
    about = "Detect duplicate functions (Rust, JavaScript, TypeScript)"
)]
struct Cli {
    #[arg(help = "Paths to scan (files or directories)")]
    paths: Vec<String>,

    #[arg(long, default_value = "0.82", help = "Jaccard similarity threshold")]
    threshold: f64,

    #[arg(long, default_value = "4", help = "Minimum source lines")]
    min_lines: usize,

    #[arg(long, default_value = "20", help = "Minimum normalized AST nodes")]
    min_nodes: usize,

    #[arg(long, default_value = "text", help = "Output format: text or json")]
    format: String,

    #[arg(
        long,
        help = "Force language (rust, js, or ts); default: auto-detect by extension"
    )]
    lang: Option<String>,

    #[arg(long, help = "Exclude glob patterns (repeatable)")]
    exclude: Vec<String>,
}

fn main() {
    let cli = Cli::parse();
    let config = Config {
        threshold: cli.threshold,
        min_lines: cli.min_lines,
        min_nodes: cli.min_nodes,
        excludes: cli.exclude,
        ..Config::default()
    };
    let result = execute_cli(&cli.paths, &cli.format, cli.lang.as_deref(), config, run);
    print!("{}", result.stdout);
    eprint!("{}", result.stderr);
    process::exit(result.exit_code);
}

